import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch8: CareerQuestion[] = [
  { id: "ota-1701", stem: "An OTA is working with a client who has a peripheral nerve injury affecting the radial nerve at the spiral groove. Which functional limitation is expected?", options: ["Loss of thumb opposition", "Wrist drop with inability to extend the wrist, fingers, and thumb", "Claw hand deformity", "Loss of finger abduction only"], correctIndex: 1, rationale: "Radial nerve injury at the spiral groove causes wrist drop (loss of wrist, finger, and thumb extensors). The client cannot stabilize the wrist for grip, significantly reducing hand function.", difficulty: 2, category: "Anatomy & Physiology", topic: "radial nerve spiral groove" },
  { id: "ota-1702", stem: "Which bone forms the anatomical snuffbox and is most commonly fractured in a fall on an outstretched hand (FOOSH)?", options: ["Lunate", "Scaphoid (navicular) — at risk for avascular necrosis due to retrograde blood supply", "Triquetrum", "Hamate"], correctIndex: 1, rationale: "The scaphoid is the most commonly fractured carpal bone (FOOSH injury). Its retrograde blood supply puts it at risk for avascular necrosis, especially with proximal pole fractures.", difficulty: 2, category: "Anatomy & Physiology", topic: "scaphoid fracture" },
  { id: "ota-1703", stem: "The ulnar nerve passes through which anatomical structure at the elbow, making it vulnerable to compression?", options: ["Carpal tunnel", "Cubital tunnel (between the medial epicondyle and olecranon)", "Guyon's canal", "Radial tunnel"], correctIndex: 1, rationale: "The ulnar nerve passes through the cubital tunnel at the medial elbow. Compression causes cubital tunnel syndrome with numbness in the ring/little fingers and weakness of intrinsic muscles.", difficulty: 2, category: "Anatomy & Physiology", topic: "cubital tunnel anatomy" },
  { id: "ota-1704", stem: "Which muscle is primarily responsible for forearm pronation?", options: ["Biceps brachii", "Pronator teres and pronator quadratus", "Supinator", "Brachioradialis"], correctIndex: 1, rationale: "Pronator teres (proximal forearm) and pronator quadratus (distal forearm) are the primary pronators. The pronator teres also assists with elbow flexion.", difficulty: 1, category: "Anatomy & Physiology", topic: "forearm pronation" },
  { id: "ota-1705", stem: "A client has a positive Finkelstein's test. Which condition does this suggest?", options: ["Carpal tunnel syndrome", "De Quervain's tenosynovitis — inflammation of the APL and EPB tendons at the first dorsal compartment", "Trigger finger", "Dupuytren's contracture"], correctIndex: 1, rationale: "Finkelstein's test: the patient makes a fist over the thumb, then the examiner ulnarly deviates the wrist. Pain at the radial styloid suggests de Quervain's tenosynovitis.", difficulty: 2, category: "Anatomy & Physiology", topic: "de Quervain's test" },
  { id: "ota-1706", stem: "The intrinsic muscles of the hand are primarily innervated by which nerve(s)?", options: ["Radial nerve only", "Ulnar nerve (most intrinsics) and median nerve (thenar muscles and lateral two lumbricals)", "Musculocutaneous nerve", "Axillary nerve"], correctIndex: 1, rationale: "Hand intrinsics: ulnar nerve innervates most (interossei, medial 2 lumbricals, hypothenar, adductor pollicis). Median nerve innervates thenar muscles and lateral 2 lumbricals.", difficulty: 2, category: "Anatomy & Physiology", topic: "hand intrinsic innervation" },
  { id: "ota-1707", stem: "An OTA is treating a client with de Quervain's tenosynovitis. Which activity modification should be recommended?", options: ["Increase repetitive thumb use", "Avoid repetitive thumb abduction and extension; use ergonomic tools with larger grips to reduce pinch force", "Only rest with no activity", "Maximum resistance thumb exercises"], correctIndex: 1, rationale: "De Quervain's modifications: avoid repetitive thumb use, ergonomic tools (larger grips), thumb spica splint for rest, ice for inflammation, and gradual return to activity.", difficulty: 1, category: "Musculoskeletal", topic: "de Quervain's activity modification" },
  { id: "ota-1708", stem: "A client with a proximal humerus fracture is in a sling. Which exercises should the OTA encourage during immobilization?", options: ["Shoulder AROM immediately", "Hand grip, wrist AROM, elbow flexion/extension (if allowed), and pendulum exercises when cleared by MD", "No exercises until fracture is healed", "Aggressive shoulder stretching"], correctIndex: 1, rationale: "During proximal humerus immobilization: maintain distal joint mobility (hand, wrist, elbow), Codman pendulum exercises when cleared, edema management, and posture education.", difficulty: 1, category: "Musculoskeletal", topic: "humerus fracture early rehab" },
  { id: "ota-1709", stem: "A client with a Colles fracture has been out of the cast for 2 weeks. What is the primary treatment focus?", options: ["Maximum resistance immediately", "Restore wrist and forearm ROM (flexion, extension, pronation, supination), finger mobility, and grip strength", "Only ice and rest", "Aggressive passive stretching"], correctIndex: 1, rationale: "Post-cast Colles: restore wrist ROM (all planes), forearm rotation, finger motion, edema control, scar management, progressive grip strengthening, and functional activity training.", difficulty: 1, category: "Musculoskeletal", topic: "Colles fracture rehab" },
  { id: "ota-1710", stem: "A client with epicondylitis should use which type of brace during functional activities?", options: ["Wrist cock-up splint", "Counterforce (forearm) strap placed 1-2 inches distal to the epicondyle to reduce tendon stress", "Thumb spica splint", "Full arm cast"], correctIndex: 1, rationale: "A counterforce strap (1-2 inches distal to the epicondyle) reduces the pull on the tendon origin by dispersing forces through the strap. Used during activities, combined with activity modification.", difficulty: 1, category: "Musculoskeletal", topic: "epicondylitis bracing" },
  { id: "ota-1711", stem: "A client with a shoulder rotator cuff repair is at 6 weeks post-surgery. What exercise progression is typical?", options: ["Full active ROM and strengthening", "Begin active-assisted ROM progressing to active ROM; strengthening typically begins at 8-12 weeks per surgeon protocol", "Continue passive ROM only", "Return to all activities"], correctIndex: 1, rationale: "Rotator cuff repair at 6 weeks: transition from PROM to AAROM, then AROM. Strengthening typically begins at 8-12 weeks. Follow surgeon protocol closely.", difficulty: 2, category: "Musculoskeletal", topic: "rotator cuff repair timeline" },
  { id: "ota-1712", stem: "An OTA is treating a client with a metacarpal fracture (boxer's fracture). Which precaution applies?", options: ["Immediate full grip activities", "Immobilize the fracture per protocol; maintain mobility of uninvolved fingers; avoid resistive gripping until cleared", "No precautions needed", "Maximum wrist flexion exercises"], correctIndex: 1, rationale: "Boxer's fracture (5th metacarpal neck): immobilize per protocol (ulnar gutter splint), maintain uninvolved finger ROM, edema management, and avoid resistive activities until fracture healing confirmed.", difficulty: 2, category: "Musculoskeletal", topic: "metacarpal fracture" },
  { id: "ota-1713", stem: "A client with a right CVA has difficulty with spatial relationships and demonstrates constructional apraxia. Which ADL is MOST affected?", options: ["Verbal communication", "Dressing (difficulty orienting clothing, distinguishing front/back, inside/outside)", "Swallowing", "Breathing exercises"], correctIndex: 1, rationale: "Constructional apraxia (right CVA) significantly impacts dressing: difficulty orienting garments spatially (inside/outside, front/back), sequencing steps, and managing fasteners.", difficulty: 2, category: "Neurological", topic: "constructional apraxia ADL" },
  { id: "ota-1714", stem: "A client with a TBI demonstrates anterograde amnesia. What does this mean?", options: ["Cannot recall events before the injury", "Cannot form new memories after the injury — difficulty learning new information and routines", "Has intact memory function", "Only short-term memory is affected"], correctIndex: 1, rationale: "Anterograde amnesia: inability to form new memories after the injury. Retrograde amnesia: inability to recall events before the injury. Both can coexist in TBI.", difficulty: 2, category: "Neurological", topic: "TBI memory types" },
  { id: "ota-1715", stem: "Which visual deficit involves inability to recognize familiar faces?", options: ["Hemianopsia", "Prosopagnosia — inability to recognize faces despite intact visual acuity (face blindness)", "Diplopia", "Scotoma"], correctIndex: 1, rationale: "Prosopagnosia (face blindness): inability to recognize familiar faces despite intact vision. Usually results from damage to the fusiform face area. The client may use voice or other cues for identification.", difficulty: 3, category: "Neurological", topic: "prosopagnosia" },
  { id: "ota-1716", stem: "An OTA is working with a client who demonstrates Broca's aphasia. What communication strategies are appropriate?", options: ["Speak faster and louder", "Use yes/no questions, allow extra time, provide visual cues, and use gestures; the client understands but has difficulty producing speech", "Only written communication", "Ignore the communication deficit"], correctIndex: 1, rationale: "Broca's (expressive) aphasia: comprehension is relatively intact, but speech production is impaired. Use yes/no questions, communication boards, gestures, and allow extra response time.", difficulty: 2, category: "Neurological", topic: "Broca's aphasia strategies" },
  { id: "ota-1717", stem: "A client with a spinal cord injury at T4 is at risk for autonomic dysreflexia. Which symptom requires immediate attention?", options: ["Mild hunger", "Sudden pounding headache, facial flushing, sweating above the level, and dangerously elevated blood pressure", "Mild shoulder pain", "Feeling slightly warm"], correctIndex: 1, rationale: "Autonomic dysreflexia (T6 and above): pounding headache, hypertension, flushing/sweating above lesion, and bradycardia. Emergency: sit up, find/remove noxious stimulus (full bladder, constipation, pressure).", difficulty: 2, category: "Neurological", topic: "autonomic dysreflexia signs" },
  { id: "ota-1718", stem: "An OTA is grading a therapeutic activity for a client with hemiplegia. Which principle guides activity grading?", options: ["Always use the hardest level", "Adjust complexity, assistance level, and environmental demands to match the client's current abilities, then progressively increase challenge", "Keep difficulty constant", "Only decrease difficulty over time"], correctIndex: 1, rationale: "Activity grading: match current ability level, then systematically increase challenge (complexity, speed, resistance, number of steps, environmental distractions) as the client improves.", difficulty: 1, category: "Rehabilitation Principles", topic: "activity grading" },
  { id: "ota-1719", stem: "Which learning theory emphasizes that behavior is shaped by consequences (reinforcement and punishment)?", options: ["Cognitive theory", "Operant conditioning (Skinner) — behavior is strengthened by reinforcement and weakened by punishment", "Humanistic theory", "Social learning theory"], correctIndex: 1, rationale: "Operant conditioning: positive reinforcement (reward) strengthens behavior, negative reinforcement (removing aversive stimulus) strengthens behavior, and punishment weakens behavior.", difficulty: 2, category: "Rehabilitation Principles", topic: "operant conditioning" },
  { id: "ota-1720", stem: "An OTA is using a task-oriented approach in rehabilitation. What is the key principle?", options: ["Focus on muscle strengthening only", "Practice functional tasks in their natural context; the brain organizes movement around functional goals, not isolated muscle actions", "Only use preparatory activities", "Focus on reflexes first"], correctIndex: 1, rationale: "Task-oriented approach: practice whole functional tasks in natural contexts. The nervous system organizes movement around functional goals. Varied practice promotes adaptable motor programs.", difficulty: 2, category: "Rehabilitation Principles", topic: "task-oriented approach" },
  { id: "ota-1721", stem: "Which type of feedback provides information about the outcome of a movement?", options: ["Knowledge of performance (KP)", "Knowledge of results (KR) — information about the outcome of the movement in relation to the goal", "Intrinsic feedback", "Proprioceptive feedback"], correctIndex: 1, rationale: "KR (knowledge of results): information about movement outcome relative to the goal (e.g., 'You walked 20 feet'). KP (knowledge of performance): information about the movement pattern.", difficulty: 2, category: "Rehabilitation Principles", topic: "KR feedback" },
  { id: "ota-1722", stem: "An OTA is teaching a client with hemiplegia to perform a sliding board transfer. What is the correct technique?", options: ["Transfer toward the affected side", "Position the board bridging both surfaces, scoot to the edge, lean away from the transfer direction, and slide across leading with the unaffected side", "Stand up and pivot", "Use a mechanical lift"], correctIndex: 1, rationale: "Sliding board transfer: remove wheelchair armrest, position board securely, scoot forward, lean away and push/slide across the board. Transfer toward the stronger/unaffected side.", difficulty: 1, category: "Patient Mobility", topic: "sliding board transfer" },
  { id: "ota-1723", stem: "A client with a lower extremity amputation is practicing donning a prosthesis with a pin-lock liner. What is the correct sequence?", options: ["Put on prosthesis first, then liner", "Roll on the liner (no wrinkles), push the pin into the shuttle lock until it clicks, then stand and check alignment", "Just push the leg in", "Apply adhesive to the socket"], correctIndex: 1, rationale: "Pin-lock system: roll liner onto residual limb (no wrinkles/air pockets), align the pin with the shuttle lock opening, push firmly until the pin clicks into the lock, then stand and verify fit.", difficulty: 2, category: "Patient Mobility", topic: "pin-lock prosthesis donning" },
  { id: "ota-1724", stem: "An OTA is training a client with bilateral hip replacements in car transfers. Which precaution applies?", options: ["Sit normally in any car", "Recline the seat back, lead with the buttocks, maintain hip precautions, use a swivel cushion, and avoid low seats", "Only ride in SUVs", "No car travel for 6 months"], correctIndex: 1, rationale: "Bilateral THR car transfers: recline the seat, back into the car leading with buttocks, maintain precautions, use a swivel cushion or plastic bag on seat for sliding, and avoid low-seat vehicles.", difficulty: 2, category: "Patient Mobility", topic: "car transfer hip precautions" },
  { id: "ota-1725", stem: "A client with quadriplegia at C5 has which functional mobility expectation?", options: ["Independent walking", "Dependent to maximal assistance for transfers; power wheelchair with hand controls or sip-and-puff", "Independent manual wheelchair propulsion", "No mobility possible"], correctIndex: 1, rationale: "C5 SCI: biceps (elbow flexion) but no triceps, wrist extensors, or hand function. Power wheelchair with adapted joystick or sip-and-puff. Dependent for most transfers; may assist with mobile arm supports.", difficulty: 2, category: "Patient Mobility", topic: "C5 mobility expectations" },
  { id: "ota-1726", stem: "An OTA is teaching a client with diabetes about foot inspection. What should the client check for daily?", options: ["Only color of toenails", "Redness, blisters, cuts, cracks, calluses, swelling, temperature changes, and any skin breakdown", "Nothing specific", "Only between toes"], correctIndex: 1, rationale: "Daily diabetic foot inspection: check all surfaces (use mirror for soles) for redness, blisters, cuts, cracks, calluses, swelling, temperature changes, and ingrown toenails. Report any findings.", difficulty: 1, category: "Patient Education", topic: "diabetic foot inspection" },
  { id: "ota-1727", stem: "A client with a new diagnosis of osteoporosis asks about exercise. What guidance should the OTA provide?", options: ["Avoid all exercise", "Weight-bearing exercise and resistance training are beneficial; avoid trunk flexion under load due to vertebral fracture risk", "Only swimming", "Maximum intensity exercise"], correctIndex: 1, rationale: "Osteoporosis exercise: weight-bearing (walking, stairs), resistance training, balance exercises (fall prevention), extension-based posture training. AVOID trunk flexion under load (fracture risk).", difficulty: 1, category: "Patient Education", topic: "osteoporosis exercise guidance" },
  { id: "ota-1728", stem: "When teaching a client about home safety, which room has the highest injury risk for falls?", options: ["Living room", "Bathroom — wet surfaces, transfers, confined space, and often lacking grab bars", "Bedroom", "Kitchen"], correctIndex: 1, rationale: "The bathroom is the highest fall-risk area: wet/slippery surfaces, confined space, tub/toilet transfers, often lacks grab bars. Recommendations: grab bars, non-slip mats, shower chair, adequate lighting.", difficulty: 1, category: "Patient Education", topic: "bathroom fall risk" },
  { id: "ota-1729", stem: "A client asks the OTA about proper lifting technique. What are the key principles?", options: ["Bend at the waist", "Keep the load close, bend at the knees, maintain neutral spine, tighten core, avoid twisting, and push/pull rather than lift when possible", "Lift with arms extended", "Use one hand only"], correctIndex: 1, rationale: "Proper lifting: close to body, bend knees (not waist), neutral spine, engage core, avoid twisting, push/pull rather than lift, and get help or use equipment for heavy loads.", difficulty: 1, category: "Patient Education", topic: "proper lifting technique" },
  { id: "ota-1730", stem: "An OTA is educating a client about the importance of a consistent sleep routine. Which recommendation is evidence-based?", options: ["Nap for 4 hours daily", "Consistent wake/sleep times, cool dark room, avoid screens 1 hour before bed, limit caffeine after noon, and relaxation routine", "Screen time until falling asleep", "Exercise vigorously before bed"], correctIndex: 1, rationale: "Sleep hygiene: consistent schedule (even weekends), cool/dark/quiet room, avoid screens 1 hour before bed, limit caffeine after noon, relaxation routine, and avoid large meals before bed.", difficulty: 1, category: "Patient Education", topic: "sleep hygiene education" },
  { id: "ota-1731", stem: "A geriatric client has significant hip flexion contracture limiting mobility. Which positioning strategy helps?", options: ["Seated all day", "Prone lying for 20-30 minutes several times daily to stretch hip flexors; avoid prolonged sitting", "Side-lying in fetal position", "Standing frame only"], correctIndex: 1, rationale: "Hip flexion contracture: prone lying stretches hip flexors, limit prolonged sitting (contributes to contracture), active hip extension exercises, and gradual standing tolerance program.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "hip contracture management" },
  { id: "ota-1732", stem: "An elderly client has decreased balance and reports fear of falling. Which intervention addresses both the physical and psychological components?", options: ["Only strengthening exercises", "Tai Chi or balance exercise program combined with cognitive-behavioral strategies for fall self-efficacy and fear reduction", "Advise the client to avoid all activity", "Wheelchair only"], correctIndex: 1, rationale: "Fear of falling intervention: progressive balance training (builds competence), cognitive strategies (reducing catastrophizing), Tai Chi (balance + confidence), and gradual exposure to challenging situations.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "fear of falling intervention" },
  { id: "ota-1733", stem: "A geriatric client with mild cognitive impairment needs help maintaining daily routines. Which strategy is MOST effective?", options: ["No strategy needed", "External memory aids: daily calendar, written schedules, phone reminders, labeled storage, and consistent routines", "Complex variable schedules", "Only verbal reminders from family"], correctIndex: 1, rationale: "Mild cognitive impairment: external memory aids (calendars, written schedules, reminders), consistent daily routine, labeled storage/organization, and caregiver education on supportive strategies.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "MCI daily routine strategies" },
  { id: "ota-1734", stem: "An elderly client has reduced grip strength affecting jar opening and can management. Which adaptation helps?", options: ["Stronger grip exercises only", "Rubber jar openers, electric can opener, lever-style faucet handles, and enlarged grip handles on utensils", "No adaptations available", "Only practice more"], correctIndex: 1, rationale: "Reduced grip adaptations: rubber jar openers, electric openers, lever handles, enlarged/built-up grips, non-slip mats, and spring-loaded scissors. Maintains independence despite weakness.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "grip weakness adaptations" },
  { id: "ota-1735", stem: "A child with sensory processing difficulties demonstrates gravitational insecurity. What does this mean?", options: ["Normal response to movement", "Excessive fear and anxiety when feet leave the ground or when experiencing unexpected movement through space", "Craving intense vestibular input", "Only visual processing issues"], correctIndex: 1, rationale: "Gravitational insecurity: excessive fear/anxiety with movement through space, especially when feet leave the ground. Related to vestibular over-responsivity. Intervention: slow, predictable, child-controlled movement.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "gravitational insecurity" },
  { id: "ota-1736", stem: "At what age does a typically developing child demonstrate mature pincer grasp (tip-to-tip)?", options: ["3 months", "9-12 months", "24 months", "36 months"], correctIndex: 1, rationale: "Pincer grasp development: inferior pincer (8-9 months), superior/neat pincer (10-12 months). By 12 months, the child uses tip-to-tip pincer for small objects (finger feeding, picking up small items).", difficulty: 1, category: "Pediatric Rehabilitation", topic: "pincer grasp age" },
  { id: "ota-1737", stem: "A child with autism spectrum disorder has restricted, repetitive behaviors. Which therapeutic approach addresses these?", options: ["Force the child to stop behaviors", "Understand the sensory function of the behavior, provide acceptable alternatives, use visual supports, and implement a sensory diet", "Ignore all behaviors", "Only medication"], correctIndex: 1, rationale: "ASD repetitive behaviors: understand function (sensory regulation, anxiety reduction), provide acceptable alternatives, visual supports, sensory diet for self-regulation, and structured transitions.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "ASD repetitive behaviors" },
  { id: "ota-1738", stem: "Which hand skill is necessary for in-hand manipulation (translation, shift, rotation)?", options: ["Only gross grasp", "Separation of the radial and ulnar sides of the hand (skilled radial side for manipulation, ulnar side for stabilization)", "Only bilateral coordination", "Only visual tracking"], correctIndex: 1, rationale: "In-hand manipulation requires hand separation: radial side (thumb, index, middle) for skilled manipulation, while the ulnar side (ring, little) stabilizes objects. Essential for pencil rotation, coin manipulation.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "in-hand manipulation" },
  { id: "ota-1739", stem: "A child with cerebral palsy demonstrates cortical thumb (persistent thumb-in-palm). Which intervention addresses this?", options: ["Ignore it", "Thumb abduction splinting, weight-bearing through the affected hand, stretching of the adductor pollicis, and functional activities promoting thumb opposition", "Only surgical intervention", "Taping the fingers together"], correctIndex: 1, rationale: "Cortical thumb intervention: thumb abduction splint (opens web space), weight-bearing (inhibits flexion), stretching adductor pollicis, and activities promoting thumb opposition/abduction.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "cortical thumb intervention" },
  { id: "ota-1740", stem: "An OTA is using constraint-induced movement therapy principles with a child who has hemiplegic CP. What does this involve?", options: ["Constraining the affected arm", "Restraining the non-affected hand while providing intensive practice with the affected hand in functional play activities", "No movement of any limb", "Only passive ROM to the affected arm"], correctIndex: 1, rationale: "Pediatric mCIMT: restrain the non-affected hand, intensive practice with the affected hand (2-6 hours/day), functional play activities, and shaping (gradual increase in difficulty).", difficulty: 2, category: "Pediatric Rehabilitation", topic: "pediatric CIMT" },
  { id: "ota-1741", stem: "A client with a CVA demonstrates spasticity in the upper extremity flexor pattern. Which splint helps manage this?", options: ["Dynamic flexion splint", "Resting hand splint or dorsal-based anti-spasticity splint positioning the hand in a reflex-inhibiting pattern (extension)", "Buddy taping all fingers", "No splinting for spasticity"], correctIndex: 1, rationale: "Spasticity management splinting: resting hand splint or anti-spasticity splint in reflex-inhibiting position (wrist extension, finger extension/abduction, thumb abduction). Reduces tone and prevents contracture.", difficulty: 2, category: "Neurological Rehabilitation", topic: "anti-spasticity splinting" },
  { id: "ota-1742", stem: "An OTA is treating a client with post-stroke central post-stroke pain (CPSP). What characterizes this condition?", options: ["Peripheral nerve pain", "Burning, aching, or lancinating pain in areas affected by the stroke, caused by thalamic or central nervous system damage", "Only musculoskeletal pain", "Pain that resolves quickly"], correctIndex: 1, rationale: "CPSP (previously thalamic pain): central neuropathic pain from thalamic or CNS damage. Burning, aching, lancinating quality in stroke-affected areas. Treatment: desensitization, medications, mirror therapy.", difficulty: 3, category: "Neurological Rehabilitation", topic: "central post-stroke pain" },
  { id: "ota-1743", stem: "Which technique facilitates trunk rotation and weight-shifting in a client with hemiplegia during sitting activities?", options: ["Keep the client perfectly still", "PNF trunk patterns, reaching across midline, bilateral arm activities, and weight-shifting exercises on a stable surface", "Only supported sitting", "Passive trunk rotation only"], correctIndex: 1, rationale: "Trunk control facilitation: PNF trunk patterns, reaching across midline (active weight shift), bilateral arm activities (hands clasped), progressive surface instability, and functional reaching tasks.", difficulty: 2, category: "Neurological Rehabilitation", topic: "trunk control facilitation" },
  { id: "ota-1744", stem: "A client with Parkinson's disease has difficulty with dual-task performance. What strategy helps?", options: ["Always perform two tasks simultaneously", "Break tasks into single-task components, practice each separately, then gradually reintroduce dual-task conditions with cueing", "Avoid all multi-step tasks", "No effective strategy exists"], correctIndex: 1, rationale: "PD dual-task difficulty: focus on one task at a time (stop walking to talk), practice tasks separately, gradually add dual-task conditions with external cues, and use attention strategies.", difficulty: 2, category: "Neurological Rehabilitation", topic: "PD dual-task strategies" },
  { id: "ota-1745", stem: "An OTA is treating a client with a healing Achilles tendon repair. What is the typical early rehabilitation focus?", options: ["Full weight-bearing immediately", "Non-weight-bearing in cast/boot, gentle ankle PROM as allowed by protocol, and prevention of joint stiffness in uninvolved joints", "Running exercises", "Maximum calf raises"], correctIndex: 1, rationale: "Early Achilles repair rehab: NWB or protected WB in boot (plantarflexion position), gentle PROM as protocol allows (progressive dorsiflexion), uninvolved joint ROM, and upper body conditioning.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Achilles repair early rehab" },
  { id: "ota-1746", stem: "A client post-ORIF of a distal radius fracture is 10 weeks out and still has significant stiffness. Which modality is indicated before ROM exercises?", options: ["Ice only", "Moist heat or paraffin wax to increase tissue extensibility before stretching/ROM exercises", "Ultrasound at maximum intensity", "No modality needed"], correctIndex: 1, rationale: "Pre-ROM modalities for stiffness: moist heat or paraffin increases tissue extensibility (collagen lengthening at elevated temperatures). Follow immediately with AROM/PROM exercises.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "modality for stiffness" },
  { id: "ota-1747", stem: "A client with a shoulder labral repair (SLAP repair) has which post-surgical restriction?", options: ["No restrictions", "Avoid combined abduction and external rotation (apprehension position), and limit overhead activities per surgeon protocol", "Only flexion restriction", "Full activity immediately"], correctIndex: 1, rationale: "SLAP repair precautions: avoid apprehension position (abduction + ER), limit overhead activities, progress ROM per surgeon protocol, and begin strengthening typically at 8-12 weeks.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "SLAP repair precautions" },
  { id: "ota-1748", stem: "An OTA is performing scar management after a flexor tendon repair. When can deep friction massage begin?", options: ["Immediately post-surgery", "Once the wound is fully healed and the tendon is strong enough to tolerate forces (typically 8-12 weeks post-repair)", "6 months post-surgery", "Never for tendon repairs"], correctIndex: 1, rationale: "Deep friction massage after flexor tendon repair: once the wound is healed and tendon can tolerate forces (8-12 weeks). Earlier scar management uses gentle techniques (silicone, light massage around the scar).", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "tendon repair scar management" },
  { id: "ota-1749", stem: "A client has a frozen shoulder in the 'thawing' phase. What is the rehabilitation approach?", options: ["No treatment — just wait", "Progressive ROM exercises (AROM, AAROM, PROM), joint mobilization, functional activities, and gradual strengthening", "Maximum force stretching", "Only ice and rest"], correctIndex: 1, rationale: "Thawing phase: ROM gradually improves. Capitalize with progressive stretching (AROM → AAROM → PROM), joint mobilization, functional reaching activities, and begin gentle strengthening.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "frozen shoulder thawing" },
  { id: "ota-1750", stem: "An OTA is treating a client with complex hand trauma including multiple digit fractures and tendon injuries. What is the priority?", options: ["Immediate full hand function", "Edema control, wound care, splinting for tissue healing, gentle motion within safe limits, and pain management", "Aggressive ROM immediately", "Only grip strengthening"], correctIndex: 1, rationale: "Complex hand trauma priorities: edema management (elevation, compression), wound care, appropriate splinting (protect healing structures), early controlled motion within safe limits, and pain management.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "complex hand trauma priorities" },
  { id: "ota-1751", stem: "Which documentation element demonstrates medical necessity for continued OT services?", options: ["Patient attended therapy today", "Measurable functional progress toward goals, skilled interventions required, and continued need for OT expertise to achieve functional outcomes", "Patient participated well", "Exercises completed as prescribed"], correctIndex: 1, rationale: "Medical necessity documentation: functional progress (measurable), skilled intervention justification, continued need for OT expertise (not maintainable by client alone), and prediction of continued improvement.", difficulty: 1, category: "Documentation", topic: "medical necessity documentation" },
  { id: "ota-1752", stem: "Which goal format meets the SMART criteria for OT documentation?", options: ["Patient will improve hand function", "Within 4 weeks, client will independently button 5 buttons on a shirt in <2 minutes using adapted buttonhook with 100% accuracy", "Get better at ADLs", "Improve ROM and strength"], correctIndex: 1, rationale: "SMART goal: Specific (button 5 buttons), Measurable (<2 minutes, 100% accuracy), Achievable (adapted device), Relevant (dressing independence), Time-bound (4 weeks).", difficulty: 1, category: "Documentation", topic: "SMART goal writing" },
  { id: "ota-1753", stem: "An OTA is documenting a client's treatment session. What is the most important principle?", options: ["Write as little as possible", "Document objectively, include measurable data, relate to functional goals, and record skilled interventions with clinical rationale", "Copy the previous note", "Only document billing information"], correctIndex: 1, rationale: "Documentation principles: objective language, measurable data, functional goal connection, skilled intervention description, clinical reasoning, and compliance with facility and payer requirements.", difficulty: 1, category: "Documentation", topic: "documentation principles" },
  { id: "ota-1754", stem: "When must the OTA obtain the supervising OT's co-signature on documentation?", options: ["Never", "According to state practice acts and facility policies — many states require OT co-signature on evaluations, discharge summaries, and treatment plans", "Only on initial evaluations", "On every note regardless"], correctIndex: 1, rationale: "Co-signature requirements vary by state law and facility policy. Generally: initial evaluations, treatment plans, discharge summaries, and progress notes may require OT co-signature. Check state regulations.", difficulty: 1, category: "Documentation", topic: "co-signature requirements" },
  { id: "ota-1755", stem: "An OTA notices that a client's functional status is declining despite treatment. What is the appropriate documentation action?", options: ["Continue documenting improvement", "Document the decline objectively, notify the supervising OT, recommend re-evaluation, and consider treatment modification or discharge", "Stop documenting", "Change the goals to match lower function"], correctIndex: 1, rationale: "Declining function: document objectively, contact the supervising OT for re-evaluation, consider treatment plan modification, assess barriers (medical, psychosocial), and discuss prognosis/discharge planning.", difficulty: 1, category: "Documentation", topic: "documenting decline" },
  { id: "ota-1756", stem: "Which infection control practice is the SINGLE most effective measure to prevent healthcare-associated infections?", options: ["Wearing gloves", "Hand hygiene — proper handwashing or alcohol-based hand rub before and after every patient contact", "Wearing a mask", "Environmental cleaning"], correctIndex: 1, rationale: "Hand hygiene is the single most effective infection prevention measure. WHO's 5 Moments: before patient contact, before clean/aseptic procedure, after body fluid exposure, after patient contact, after touching surroundings.", difficulty: 1, category: "Infection Prevention", topic: "hand hygiene importance" },
  { id: "ota-1757", stem: "A client is on droplet precautions. What PPE is required?", options: ["N95 respirator", "Surgical mask when within 3-6 feet of the patient; gloves and gown if potential for contact", "No PPE required", "Full body suit"], correctIndex: 1, rationale: "Droplet precautions: surgical mask within 3-6 feet, door can remain open (unlike airborne). Examples: influenza, pertussis, meningococcal disease, and some respiratory viruses.", difficulty: 1, category: "Infection Prevention", topic: "droplet precautions PPE" },
  { id: "ota-1758", stem: "How should the OTA clean therapy equipment between patients?", options: ["No cleaning needed", "Disinfect all surfaces with facility-approved disinfectant, allow proper contact time, and ensure the equipment is dry before next use", "Quick wipe with dry cloth", "Only clean if visibly soiled"], correctIndex: 1, rationale: "Equipment cleaning: use facility-approved disinfectant, follow manufacturer contact time (usually 1-3 minutes), clean all contact surfaces, and allow to dry. Clean between every patient.", difficulty: 1, category: "Infection Prevention", topic: "equipment disinfection" },
  { id: "ota-1759", stem: "A client with MRSA wound infection requires which type of precautions?", options: ["Standard precautions only", "Contact precautions — gown and gloves on entry, dedicated equipment, and hand hygiene with soap and water preferred on exit", "Airborne precautions", "Droplet precautions"], correctIndex: 1, rationale: "MRSA requires contact precautions: gown and gloves upon room entry, dedicated equipment, hand hygiene (soap and water preferred for spore-forming organisms), and proper doffing sequence.", difficulty: 1, category: "Infection Prevention", topic: "MRSA precautions" },
  { id: "ota-1760", stem: "An OTA is treating a client in a home health setting. What infection prevention measure is essential?", options: ["No special measures in home settings", "Hand hygiene before and after treatment, clean supplies, teach client/family about infection prevention, and proper waste disposal", "Only wear gloves", "Same as hospital precautions exactly"], correctIndex: 1, rationale: "Home health infection prevention: hand hygiene (carry hand sanitizer), clean supplies, teach client/family about hygiene, proper waste disposal, and maintain clean work surfaces.", difficulty: 1, category: "Infection Prevention", topic: "home health infection control" },
  { id: "ota-1761", stem: "An OTA is working with a client who has a recently placed central venous catheter (PICC line). What precaution should the OTA take during upper extremity activities?", options: ["No precautions needed", "Avoid pulling or tension on the PICC line, protect the site during activities, avoid immersing the site in water, and monitor for swelling/pain", "Remove the line for therapy", "Ignore the line during treatment"], correctIndex: 1, rationale: "PICC line precautions: avoid tension/pulling on the line, protect the insertion site, avoid submersion in water, monitor for signs of complications (swelling, pain, leaking), and avoid BP on that arm.", difficulty: 1, category: "Patient Safety", topic: "PICC line precautions" },
  { id: "ota-1762", stem: "Which clinical sign indicates a possible deep vein thrombosis (DVT) that the OTA should report immediately?", options: ["Mild muscle soreness", "Unilateral calf swelling, warmth, redness, tenderness, and positive Homan's sign (calf pain with dorsiflexion)", "Equal bilateral leg edema", "Cold extremity only"], correctIndex: 1, rationale: "DVT signs: unilateral calf/leg swelling, warmth, redness, tenderness, and possible positive Homan's sign. Report immediately — DVT is a medical emergency (risk of pulmonary embolism).", difficulty: 1, category: "Patient Safety", topic: "DVT recognition" },
  { id: "ota-1763", stem: "A client's blood pressure reading is 210/120 mmHg before therapy. What should the OTA do?", options: ["Proceed with therapy", "Do not begin treatment; report the dangerously elevated blood pressure to nursing/physician immediately", "Start with light exercise", "Take the blood pressure again in 30 minutes"], correctIndex: 1, rationale: "BP 210/120 is hypertensive crisis (SBP >180 and/or DBP >120). Do NOT exercise. Report immediately to physician/nursing. Can cause stroke, heart attack, or organ damage.", difficulty: 1, category: "Patient Safety", topic: "hypertensive crisis" },
  { id: "ota-1764", stem: "An OTA is working with a client who has epilepsy. What safety precaution should be in place during therapy?", options: ["No special precautions", "Know seizure type and protocol, clear area of hazards, position safely if seizure occurs, time the seizure, and never restrain", "Restrain the client during seizures", "Insert something in the mouth during seizures"], correctIndex: 1, rationale: "Seizure precautions: know client's seizure type, clear area, position safely (side-lying), protect the head, time the seizure, do not restrain or put anything in the mouth, and call for help if >5 minutes.", difficulty: 1, category: "Patient Safety", topic: "seizure precautions" },
  { id: "ota-1765", stem: "A client has an allergy to latex documented in their chart. Which therapy supplies should the OTA avoid?", options: ["No supplies contain latex", "Latex gloves, rubber therapy bands (TheraBand — check if latex-free), balloons, and some elastic wraps", "Only latex gloves", "Nothing — latex is safe for skin contact"], correctIndex: 1, rationale: "Latex-containing therapy items: some gloves, exercise bands (check packaging), balloons, elastic wraps, and blood pressure cuffs. Use non-latex alternatives (nitrile gloves, latex-free bands).", difficulty: 1, category: "Patient Safety", topic: "latex allergy avoidance" },
  { id: "ota-1766", stem: "An OTA must ensure ethical practice when accepting gifts from clients. What is the appropriate response?", options: ["Accept all gifts freely", "Follow facility policy; generally decline gifts of significant value, as they may compromise professional boundaries", "Ask for gifts", "Accept gifts only on holidays"], correctIndex: 1, rationale: "Gift acceptance: follow facility policy, generally decline gifts of significant value or those that could create obligation/boundary issues. Small tokens (cards, baked goods) may be acceptable per policy.", difficulty: 1, category: "Professional Ethics", topic: "gift acceptance ethics" },
  { id: "ota-1767", stem: "An OTA is asked by a client's employer to provide information about the client's condition. What is the correct response?", options: ["Share all medical information", "Explain that health information is protected by HIPAA; information can only be released with the client's written authorization", "Only share the diagnosis", "Refuse to speak to the employer entirely"], correctIndex: 1, rationale: "HIPAA: health information requires written authorization for release. The OTA cannot share any health information with the employer without the client's signed consent/authorization form.", difficulty: 1, category: "Professional Ethics", topic: "HIPAA employer requests" },
  { id: "ota-1768", stem: "Which ethical principle requires the OTA to be truthful and honest with clients?", options: ["Beneficence", "Veracity — the obligation to be truthful, accurate, and honest in all professional communications", "Justice", "Nonmaleficence"], correctIndex: 1, rationale: "Veracity: the ethical obligation to be truthful and honest. Applies to documentation, communication with clients and colleagues, and representing qualifications and competencies accurately.", difficulty: 1, category: "Professional Ethics", topic: "veracity" },
  { id: "ota-1769", stem: "An OTA is treating a client and realizes the intervention being provided is outside the OTA's competence. What is the ethical response?", options: ["Continue and learn on the job", "Stop the intervention, inform the client, consult with the supervising OT, and seek appropriate training before performing the intervention", "Ask the client for guidance", "Continue but document the concern"], correctIndex: 1, rationale: "The OTA should only practice within their competence. If a treatment is beyond their skills: stop, inform the OT, seek supervision/training, and refer to a more qualified practitioner.", difficulty: 1, category: "Professional Ethics", topic: "practicing within competence" },
  { id: "ota-1770", stem: "The OTA's role in research is guided by which ethical principle?", options: ["No ethical guidelines for research", "Informed consent, beneficence (do good), nonmaleficence (do no harm), and justice (fair subject selection)", "Only institutional approval", "Only subject compensation"], correctIndex: 1, rationale: "Research ethics: informed consent (voluntary, adequate information), beneficence, nonmaleficence, justice (fair participant selection), and IRB approval. OTAs may participate in research within their scope.", difficulty: 2, category: "Professional Ethics", topic: "research ethics" },
  { id: "ota-1771", stem: "When a client asks the OTA for advice about their medication, what is the appropriate response?", options: ["Provide detailed medication advice", "Explain that medication management is outside the OTA's scope; direct the client to their physician or pharmacist", "Recommend specific medications", "Advise them to stop taking medications"], correctIndex: 1, rationale: "Medication advice is outside the OTA's scope of practice. Refer to the physician or pharmacist. The OTA can educate about medication management routines (pill organizers, schedules) within OT scope.", difficulty: 1, category: "Professional Ethics", topic: "scope of practice medications" },
  { id: "ota-1772", stem: "How should the OTA handle a client who repeatedly makes romantic advances?", options: ["Reciprocate to maintain rapport", "Set clear professional boundaries, document the behavior, consult with the supervisor, and if necessary, transfer care to another clinician", "Ignore the behavior", "End treatment immediately without explanation"], correctIndex: 1, rationale: "Maintain professional boundaries: address the behavior directly and respectfully, document, consult with the supervisor, and if behavior continues despite intervention, consider transferring care.", difficulty: 1, category: "Patient Communication", topic: "managing inappropriate advances" },
  { id: "ota-1773", stem: "An OTA is explaining a complex home modification plan to a client with limited English proficiency. What communication strategy is best?", options: ["Speak louder in English", "Use professional interpreter services, visual diagrams, demonstration, and simplified language; avoid using family members for clinical interpretation", "Use only gestures", "Write everything in English"], correctIndex: 1, rationale: "Limited English proficiency: professional medical interpreter (not family for clinical communication), visual aids/diagrams, demonstration, simplified language, and translated written materials.", difficulty: 1, category: "Patient Communication", topic: "LEP communication" },
  { id: "ota-1774", stem: "When providing feedback to a client about their performance, which approach promotes motivation and learning?", options: ["Only criticism", "Balance specific positive feedback with constructive suggestions; focus on effort and progress rather than just outcomes", "No feedback at all", "Only negative feedback to motivate improvement"], correctIndex: 1, rationale: "Effective feedback: specific (what they did well), constructive (what to adjust), effort-focused (acknowledge hard work), progress-oriented (compare to previous performance), and timely.", difficulty: 1, category: "Patient Communication", topic: "therapeutic feedback" },
  { id: "ota-1775", stem: "An OTA is conducting a home visit and the client's family member becomes hostile and threatening. What should the OTA do?", options: ["Argue with the family member", "Ensure personal safety first — calmly de-escalate if possible, leave the home if unsafe, and report the incident to the supervisor", "Continue treatment regardless", "Call the police immediately from inside the home"], correctIndex: 1, rationale: "Personal safety first: remain calm, don't argue, attempt de-escalation, leave if unsafe, report to supervisor, document the incident, and develop a safety plan for future visits.", difficulty: 1, category: "Patient Communication", topic: "home visit safety" },
  { id: "ota-1776", stem: "The OTA observes that a client is not following their home exercise program. What communication approach is MOST effective?", options: ["Scold the client", "Use motivational interviewing: explore barriers, elicit the client's own reasons for change, and collaboratively problem-solve to improve adherence", "Threaten discharge", "Ignore the non-adherence"], correctIndex: 1, rationale: "Motivational interviewing: open-ended questions (explore barriers), reflective listening, affirm client's autonomy, explore ambivalence, and collaboratively problem-solve for adherence.", difficulty: 2, category: "Patient Communication", topic: "motivational interviewing HEP" },
  { id: "ota-1777", stem: "An OTA is part of a discharge planning team. What is the OTA's primary contribution?", options: ["Financial planning", "Reporting current functional status, equipment needs, environmental modifications, and caregiver training requirements to support safe discharge", "Medical decision-making", "Social service coordination"], correctIndex: 1, rationale: "OTA discharge planning contributions: functional status report, adaptive equipment recommendations, home modification needs, caregiver training, HEP, and community resource referrals.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "OTA discharge role" },
  { id: "ota-1778", stem: "When collaborating with the speech-language pathologist about a client with dysphagia, what information should the OTA share?", options: ["Only OT goals", "Client's positioning during meals, self-feeding abilities, adaptive equipment use, and observations of swallowing difficulties during mealtimes", "Nothing — separate disciplines", "Only the client's name"], correctIndex: 1, rationale: "OTA-SLP dysphagia collaboration: share positioning observations, self-feeding ability, mealtime behavioral observations, adaptive equipment use, and any swallowing concerns noted during meals.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "SLP collaboration dysphagia" },
  { id: "ota-1779", stem: "The OTA receives a physician order to evaluate a new client. Is this appropriate?", options: ["Yes — the OTA can evaluate independently", "No — the initial evaluation must be performed by the OT; the OTA should contact the supervising OT to schedule the evaluation", "Only if the OT is on vacation", "Only for simple cases"], correctIndex: 1, rationale: "Initial evaluation is an OT-only responsibility. The OTA should forward the referral/order to the supervising OT. The OTA may assist with data collection but the OT interprets and establishes the plan of care.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "OTA evaluation scope" },
  { id: "ota-1780", stem: "How should the OTA collaborate with nursing staff regarding a client's ADL performance?", options: ["Work independently without communication", "Share functional abilities, adaptive techniques, and equipment training so nursing can reinforce consistency in ADL performance across shifts", "Only communicate through the OT", "Only at formal meetings"], correctIndex: 1, rationale: "OTA-nursing collaboration: educate nursing on adaptive techniques, equipment use, and functional abilities so they can reinforce independence consistently. Nursing observes 24/7 and can provide valuable input.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "nursing collaboration" },
  { id: "ota-1781", stem: "A client with a new spinal cord injury is depressed and refusing to participate in therapy. How should the interdisciplinary team address this?", options: ["Force participation", "Psychology/social work for counseling, OT/PT for gradual engagement, physician for medication review, and peer support referral", "Discharge immediately", "Ignore the depression"], correctIndex: 1, rationale: "Interdisciplinary approach to SCI depression: psychology/social work (counseling), OT/PT (functional goals, gradual engagement), physician (medication), peer support, and family education.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "SCI depression team approach" },
  { id: "ota-1782", stem: "A 65-year-old client with diabetes, peripheral neuropathy, and a recent below-knee amputation needs rehabilitation. Which clinical considerations are MOST important?", options: ["Only prosthetic training", "Skin integrity monitoring, blood glucose management during exercise, wound healing surveillance, prosthetic fit monitoring, and fall prevention", "Only strengthening exercises", "Only gait training"], correctIndex: 1, rationale: "Diabetic BKA clinical considerations: skin integrity (neuropathy), blood glucose monitoring during exercise, wound healing, prosthetic fit surveillance, fall prevention, and cardiovascular monitoring.", difficulty: 2, category: "Clinical Case Scenarios", topic: "diabetic amputee" },
  { id: "ota-1783", stem: "A client with a TBI is in Rancho Level VI (confused, appropriate). What is the treatment approach?", options: ["Full independence in all tasks", "Structured activities with increasing complexity, community re-entry tasks, self-monitoring strategies, and moderate supervision", "Maximum assistance for everything", "Only bed-level activities"], correctIndex: 1, rationale: "Rancho VI: confusion resolving, follows simple directions, recognizes familiar people. Treatment: structured activities (graded complexity), community skills training, memory strategies, and moderate supervision.", difficulty: 2, category: "Clinical Case Scenarios", topic: "TBI Rancho VI treatment" },
  { id: "ota-1784", stem: "A client with bilateral hand osteoarthritis has difficulty with kitchen tasks. Which combination of adaptations is MOST comprehensive?", options: ["No adaptations available", "Lever faucet handles, enlarged grip utensils, electric can/jar openers, lightweight pots, non-slip mats, and ergonomic knife (rocker knife)", "Only rest and medication", "Only one adaptation at a time"], correctIndex: 1, rationale: "Bilateral hand OA kitchen adaptations: lever handles, enlarged/built-up grips, electric openers, lightweight cookware, non-slip mats, rocker knife, loop scissors, and ergonomic tools.", difficulty: 1, category: "Clinical Case Scenarios", topic: "bilateral hand OA kitchen" },
  { id: "ota-1785", stem: "A client with a progressive neurological condition (ALS) is losing hand function. When should adaptive equipment be introduced?", options: ["Only when function is completely lost", "Proactively — introduce adaptive equipment early while the client can learn to use it, before function is completely lost", "Never — focus on restoration", "Only at family's request"], correctIndex: 1, rationale: "Progressive conditions: introduce adaptive equipment proactively (while learning ability is intact). Early introduction allows time for training, adaptation, and acceptance before function deteriorates further.", difficulty: 2, category: "Clinical Case Scenarios", topic: "progressive condition equipment timing" },
  { id: "ota-1786", stem: "A client with chronic pain demonstrates pain catastrophizing. Which OT intervention addresses this?", options: ["Only passive pain relief modalities", "Cognitive-behavioral approach: identify catastrophizing thoughts, challenge them, develop realistic expectations, and use graded activity exposure", "Ignore the psychological component", "Maximum rest until pain-free"], correctIndex: 1, rationale: "Pain catastrophizing intervention: cognitive restructuring (identify/challenge catastrophizing thoughts), pain neuroscience education, graded activity exposure, relaxation training, and functional goal focus.", difficulty: 2, category: "Clinical Case Scenarios", topic: "pain catastrophizing intervention" },
  { id: "ota-1787", stem: "An OTA is developing a rehabilitation plan for a client returning to work after a hand injury. What should the plan include?", options: ["Only hand exercises", "Work task analysis, job simulation, graded work hardening/conditioning, ergonomic modifications, and coordination with the employer", "Only strengthening", "Return to work immediately"], correctIndex: 1, rationale: "Return-to-work planning: work task analysis (physical demands), job simulation activities, graded work hardening, ergonomic assessment/modifications, and employer communication about accommodations.", difficulty: 2, category: "Rehabilitation Planning", topic: "return to work hand injury" },
  { id: "ota-1788", stem: "When developing a community reintegration plan for a client with TBI, which activities should be practiced?", options: ["Only in-clinic activities", "Grocery shopping, money handling, public transportation, social situations, and community safety skills in progressively complex environments", "Only driving", "Only conversation skills"], correctIndex: 1, rationale: "TBI community reintegration: grocery shopping, money management, transportation use, social skills, community safety, problem-solving in real-world settings, and progressive environmental complexity.", difficulty: 1, category: "Rehabilitation Planning", topic: "TBI community reintegration" },
  { id: "ota-1789", stem: "A client with multiple sclerosis needs a comprehensive energy management plan. What elements should be included?", options: ["Ignore fatigue", "Activity diary (identify energy patterns), task prioritization, pacing with rest breaks, environmental modification, adaptive equipment, and sleep hygiene", "Exercise through all fatigue", "Only medication for fatigue"], correctIndex: 1, rationale: "MS energy management: activity diary, task prioritization matrix, pacing/rest breaks, environmental modification, adaptive equipment, sleep hygiene, cooling strategies, and stress management.", difficulty: 2, category: "Rehabilitation Planning", topic: "MS energy management plan" },
  { id: "ota-1790", stem: "An OTA is planning a home modification for a client with a new wheelchair. Which features are essential?", options: ["No modifications needed", "Accessible doorways (32-36\"), ramp (1:12 slope), clear floor space, accessible bathroom (roll-in shower), and lowered counters/storage", "Only a ramp", "Only wider doorways"], correctIndex: 1, rationale: "Wheelchair home modifications: doorways 32-36\" minimum, ramp (1:12 slope), clear floor paths (36\"), accessible bathroom, accessible kitchen (lowered counters, knee clearance), and flooring changes.", difficulty: 1, category: "Rehabilitation Planning", topic: "wheelchair home modifications" },
  { id: "ota-1791", stem: "When developing a fall prevention plan for a geriatric client, which multicomponent approach has the strongest evidence?", options: ["Only environmental modification", "Exercise (balance + strength), home modification, medication review, vision correction, and education on fall risk reduction", "Only hip protectors", "Only activity restriction"], correctIndex: 1, rationale: "Evidence-based fall prevention: multicomponent approach — exercise (balance + LE strength), home hazard modification, medication review, vision correction, footwear assessment, and self-management education.", difficulty: 1, category: "Rehabilitation Planning", topic: "fall prevention plan" },
  { id: "ota-1792", stem: "An OTA is developing a HEP for a client with a rotator cuff repair. What principles guide the program?", options: ["Maximum exercises for faster recovery", "Follow surgeon protocol, progress gradually, include written and visual instructions, teach self-monitoring for overexertion, and schedule follow-up", "No HEP needed", "Only one exercise"], correctIndex: 1, rationale: "Rotator cuff HEP principles: surgeon protocol adherence, gradual progression, clear instructions (written + visual), self-monitoring education (pain, swelling indicators), and regular follow-up.", difficulty: 1, category: "Rehabilitation Planning", topic: "rotator cuff HEP" },
  { id: "ota-1793", stem: "Which therapeutic exercise uses reciprocal movements to promote coordination and bilateral integration?", options: ["Isometric holds", "Bilateral arm training (e.g., bilateral arm reaching, pushing/pulling, and rhythmic alternating movements)", "Single-arm isolation exercises", "Static postures only"], correctIndex: 1, rationale: "Bilateral arm training: reciprocal and symmetrical movements of both arms simultaneously. Evidence supports its use for post-stroke UE rehabilitation, promoting interlimb coordination.", difficulty: 2, category: "Therapeutic Exercises", topic: "bilateral arm training" },
  { id: "ota-1794", stem: "An OTA is instructing a client in nerve gliding exercises for carpal tunnel syndrome. Which technique is used?", options: ["Maximum wrist flexion", "Sequential positioning from wrist flexion to extension with varying finger and thumb positions to glide the median nerve through the carpal tunnel", "Only wrist extension", "Grip strengthening"], correctIndex: 1, rationale: "Nerve gliding for CTS: sequential positions from wrist flexion to extension with varying finger/thumb positions that progressively place tension on and glide the median nerve.", difficulty: 2, category: "Therapeutic Exercises", topic: "nerve gliding CTS" },
  { id: "ota-1795", stem: "A client needs strengthening for weak finger extensors. Which exercise targets the extensor digitorum communis?", options: ["Grip squeezing", "Reverse grip exercises: placing a rubber band around the fingertips and extending the fingers against resistance", "Wrist flexion exercises", "Bicep curls"], correctIndex: 1, rationale: "Finger extensor strengthening: rubber band resistance around fingertips (extension against resistance), reverse grip exercises, and resistive putty activities emphasizing finger extension.", difficulty: 1, category: "Therapeutic Exercises", topic: "finger extensor strengthening" },
  { id: "ota-1796", stem: "An OTA is using mirror therapy for a client with hand hemiplegia after stroke. How is this performed?", options: ["Both hands visible to the client", "Place a mirror between the hands so the reflection of the unaffected hand creates the illusion of the affected hand moving normally", "Use a screen covering both hands", "Mirror placed behind the client"], correctIndex: 1, rationale: "Mirror therapy: mirror between hands (affected hand hidden), the client watches the reflection of the unaffected hand moving, creating a visual illusion of the affected hand functioning. Promotes cortical reorganization.", difficulty: 2, category: "Therapeutic Exercises", topic: "mirror therapy technique" },
  { id: "ota-1797", stem: "A client with a wrist fracture needs to regain forearm rotation. Which exercise is MOST effective?", options: ["Wrist flexion/extension only", "Active pronation/supination with the elbow at 90° flexion, progressing from gravity-eliminated to against gravity to resistive", "Only shoulder exercises", "Grip strengthening only"], correctIndex: 1, rationale: "Forearm rotation exercises: elbow at 90°, active pronation/supination (gravity-eliminated → against gravity → resistive with dowel/dumbbell). Progress through full available ROM.", difficulty: 1, category: "Therapeutic Exercises", topic: "forearm rotation exercises" },
  { id: "ota-1798", stem: "An OTA is constructing an ADL board for a client with cognitive deficits. Which fasteners should be included?", options: ["Only zippers", "Variety of fasteners: buttons (various sizes), zippers, snaps, Velcro, hooks, buckles, and laces to practice each skill", "No fasteners — too frustrating", "Only large buttons"], correctIndex: 1, rationale: "ADL board: variety of fasteners for progressive practice — large buttons → small buttons, Velcro, snaps, zippers, hooks, buckles, and laces. Graded from simple to complex.", difficulty: 1, category: "Assistive Devices", topic: "ADL board design" },
  { id: "ota-1799", stem: "A client needs a mobile arm support (MAS) to assist with self-feeding. What condition typically requires this?", options: ["Mild shoulder weakness", "Severe proximal UE weakness (muscular dystrophy, high SCI, GBS) where the client cannot lift the arm against gravity", "Finger stiffness only", "Wrist weakness only"], correctIndex: 1, rationale: "Mobile arm supports: severe proximal UE weakness (C4-C5 SCI, muscular dystrophy, GBS). The MAS supports the arm against gravity, allowing residual distal function for feeding/activities.", difficulty: 2, category: "Assistive Devices", topic: "mobile arm support" },
  { id: "ota-1800", stem: "An OTA is recommending a rocker knife for a client. What is its primary advantage?", options: ["Cuts faster than regular knives", "Allows one-handed cutting by rocking the curved blade; no need to hold the food with a fork in the other hand", "More attractive design", "Safer than regular knives"], correctIndex: 1, rationale: "The rocker knife has a curved blade that rocks through food using one hand. Combined with a spike board or non-slip mat to stabilize food. Essential for one-handed individuals.", difficulty: 1, category: "Assistive Devices", topic: "rocker knife" },
  { id: "ota-1801", stem: "Which type of bathing equipment allows a client with balance deficits to safely bathe in a shower without a tub?", options: ["Standard bath mat only", "Roll-in shower chair or bench with back and armrests, handheld showerhead, and grab bars", "Only a tub bench", "No equipment available"], correctIndex: 1, rationale: "Shower safety equipment: roll-in shower chair/bench (back and armrests for support), handheld showerhead, grab bars, non-slip floor surface, and accessible soap/shampoo dispensers.", difficulty: 1, category: "Assistive Devices", topic: "shower safety equipment" },
];
